# Prompt: Using Python: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import redirect, request, url_for, Flask, session

app = Flask(__name__)
app.secret_key = 'your-secret-key'
USER_DATA = {
    "username": "test",
    "password": "test123"
}

@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    password = request.form['password']
    if username == USER_DATA["username"] and password == USER_DATA["password"]:
        session['logged_in'] = True
        session['next_url'] = request.args.get('next')
        return redirect(session['next_url'] if session.get('next_url') else url_for('home'))
    else:
        return "Incorrect username or password"

@app.route('/')
def home():
    if not session.get('logged_in'):
        return redirect(url_for('login', next=request.url))
    else:
        return "Welcome! You are now logged in."

if __name__=="__main__":
    app.run(debug=True)